insert into public.innovation_guild_vendors (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('4TH_P1764678674095', '4th Phase Water Technologies Pvt Ltd - Jiva Water', 'At Jiva Water Farm Devices, we believe water isn''t just a means to irrigate - it''s your farm''s most powerful input.But the water reaching your fields today is low in biological activity and less effective for soil and crop health.
Jiva Water Farm Devices are designed to address today''s agricultural challenges, from declining soil health to poor crop quality.
By reducing water''s surface tension and enhancing microbial activity, our devices help:
&#9989; Improve nutrient delivery to plants
&#9989; Boost soil moisture retention
&#9989; Reduce salt deposition
&#9989; Strengthen root-to-fruit development
&#9989; Support long-term soil health and fertility
We''re proud to work alongside progressive farmers across India, helping them grow better with smarter water practices. We''re also grateful to have Murugappa Water Technology and Services (MWTS) as a valuable partner in this journey towards sustainable agriculture.
Because in farming, Smart Water = Better Soil = Better Yield.', null, '4th Phase Water Technologies Pvt Ltd - Jiva Water, 12/2, 2nd Main Rd, below SBI, 7th Block, Jayanagar, Bengaluru, Karnataka 560070, India | Kerala, India | Maharashtra, India | Telangana, India | Karnataka, India | Odisha, India | Andhra Pradesh, India | Gujarat, India', null, null, 'India', '{"4th Phase Water Technologies Pvt Ltd - Jiva Water, 12/2, 2nd Main Rd, below SBI, 7th Block, Jayanagar, Bengaluru, Karnataka 560070, India","Kerala, India","Maharashtra, India","Telangana, India","Karnataka, India","Odisha, India","Andhra Pradesh, India","Gujarat, India"}', '{"Irrigation","purification","Agriculture","Maintenance and management"}', 'https://innovationguild.in/innovation/home', '4th Phase Water Technologies Pvt Ltd - Jiva Water', null, null, null, null, null, null, null, '4th Phase Water Technologies Pvt Ltd - Jiva Water, 12/2, 2nd Main Rd, below SBI, 7th Block, Jayanagar, Bengaluru, Karnataka 560070, India', 'https://innovationguild.in/innovation/4241/jiva-water-farm-device-vipasa-better-water-for-higher-yield-and-soil-fertility', 'Innovation Guild API does not expose organization website/email/phone', 'https://innovationguild.in/innovation/4241/jiva-water-farm-device-vipasa-better-water-for-higher-yield-and-soil-fertility', 'Address captured from Innovation Guild. Email and phone can be enriched later through organization-contact-seed.json and admin syncs.', 12.9303665, 77.57825439999999, 1, 'Jiva Water Farm Device Vipasa - Better Water for Higher Yield and Soil Fertility Vipasa is a non-electric water device, ideal for small agricultural lands, poultry, and cattle farms, designed to improve water efficiency and absorption by roots, stems, and plants. It enhances soil fertility, reduces soil salinity, and boosts crop nutritional value. With better water efficiency, it supports higher yields, faster crop cycles, and improved overall farm productivity. For poultry and cattle, consistent water quality helps maintain optimal health for livestock and supports better productivity. Built with premium-grade stainless steel, Vipasa is durable, low-maintenance, and easy to install for efficient farm irrigation. 4th Phase Water Technologies Pvt Ltd - Jiva Water Irrigation purification 4th Phase Water Technologies Pvt Ltd - Jiva Water, 12/2, 2nd Main Rd, below SBI, 7th Block, Jayanagar, Bengaluru, Karnataka 560070, India Kerala, India Maharashtra, India Telangana, India Karnataka, India Odisha, India Andhra Pradesh, India Gujarat, India', '{"organization_name":"4th Phase Water Technologies Pvt Ltd - Jiva Water","organization_code":"4TH_P1764678674095"}'::jsonb, now(), now());
insert into public.innovation_guild_vendors (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('AEDAA1723446285869', 'AEDAA EQUIPMENT', 'At AEDAA Equipments, we are dedicated to transforming the agricultural landscape through technology and AI. Our goal is to enhance crop yield, promote sustainable farming, and make high-tech farming accessible to modern farmers. We specialize in providing crop-specific water optimization, fertigation automation, and low-maintenance motor controllers, alongside advanced pest prediction and control solutions.', null, 'Gattu, Andhra Pradesh 517352, India | Rajasthan, India', null, null, 'India', '{"Gattu, Andhra Pradesh 517352, India","Rajasthan, India"}', '{"Insects Trap","Agriculture","Maintenance and management"}', 'https://innovationguild.in/innovation/home', 'AEDAA EQUIPMENT', null, null, null, null, null, null, null, 'Gattu, Andhra Pradesh 517352, India', 'https://innovationguild.in/innovation/1354/mini-solar-insect-trap', 'Innovation Guild API does not expose organization website/email/phone', 'https://innovationguild.in/innovation/1354/mini-solar-insect-trap', 'Address captured from Innovation Guild. Email and phone can be enriched later through organization-contact-seed.json and admin syncs.', 13.6610203, 78.33319279999999, 1, 'Mini Solar Insect trap Introducing our Eco-Friendly Solar-Powered Pest Controller - Perfect for Diverse Crops and Go-downs
Our innovative pest control solution harnesses the power of solar energy, making it an environmentally friendly choice for farmers and warehouse managers. Designed to suit a variety of crops, this device is ideal for use in go-downs and fields alike.
Key Features:
Solar-Powered Efficiency:- Utilizes sustainable solar energy, ensuring continuous operation without the need for external power sources. This feature not only saves energy but also reduces operational costs.
Advanced UV Attraction Technology:- Equipped with slightly visible UV light, our pest controller expertly lures flies and other insects. The pests are then efficiently trapped in the soap and oil water tank positioned beneath the light. This method is safe, non-toxic, and highly effective.
Automatic and User-Friendly:- Designed to operate automatically, this pest controller requires minimal human intervention, making it a convenient solution for busy farmers and warehouse managers.
Natural Crop Protection:- By attracting and eliminating pests, our device naturally protects crops from insect damage. This reduces the reliance on harmful chemicals and pesticides, promoting healthier crop growth and a safer environment.
Cost-Effective:- With its solar-powered design and automatic operation, this pest controller significantly reduces manpower expenses and eliminates the need for electrical power, making it a cost-effective solution for pest management.
Ideal for a range of agricultural and storage settings, our Solar-Powered Pest Controller is an innovative step towards sustainable and efficient pest management. AEDAA EQUIPMENT Insects Trap Gattu, Andhra Pradesh 517352, India Rajasthan, India', '{"organization_name":"AEDAA EQUIPMENT","organization_code":"AEDAA1723446285869"}'::jsonb, now(), now());
