insert into public.innovation_guild_vendors (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('EKATH1723274170711', 'Ekathva Innovations', 'In the mid of 2018, as a team of four young minds, we came together to innovate and solve the day to day problems of the common man by our innovative products and services. Resulting in establishing a new venture of our own, &#34;Ekathva Innovations Private Limited&#34;, at JNN College of Engineering, Shivamogga, Karnataka.', null, 'Shivamogga, Karnataka, India | Karnataka, India', null, null, 'India', '{"Shivamogga, Karnataka, India","Karnataka, India"}', '{"Irrigation","Agriculture","Maintenance and management"}', 'https://innovationguild.in/innovation/home', 'Ekathva Innovations', null, null, null, null, null, null, null, 'Shivamogga, Karnataka, India', 'https://innovationguild.in/innovation/1344/smart-irrigation-and-micro-management-systems', 'Innovation Guild API does not expose organization website/email/phone', 'https://innovationguild.in/innovation/1344/smart-irrigation-and-micro-management-systems', 'Address captured from Innovation Guild. Email and phone can be enriched later through organization-contact-seed.json and admin syncs.', 13.9299299, 75.568101, 1, 'Smart Irrigation and Micro Management Systems GPRS based IoT Gateway, along with LoRa for in farm communication ? Internet enabled device communicate with user from any part of the world
