insert into public.innovation_guild_vendors (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('GRAIN1762252229351', 'Grain Shell', 'Grain Shell is a leading innovator in agricultural storage and drying solutions, committed to addressing the critical challenges of post-harvest losses through sustainable technologies. Based in Hyderabad, India, we specialize in eco-friendly products powered by solar energy, aimed at improving the quality and longevity of agricultural commodities. Our solutions are designed with small-scale farmers in mind, helping them preserve crops, reduce waste, and maximize profitability while promoting environmental preservation. With a strong emphasis on green technology, our range of solar dryers, airtight storage bags and hermetic storage cubicles are engineered to deliver cost-effective and efficient solutions for drying and storing grains, fruits, vegetables, and other agricultural products. By empowering farmers to adopt better storage practices, we contribute to enhancing food security and ensuring that post-harvest losses are minimized.', null, 'A. S. Rao Nagar, Secunderabad, Telangana, India | Telangana, India | A. S. Rao Nagar, Secunderabad, Telangana, India | Telangana, India | Andhra Pradesh, India', null, null, 'India', '{"A. S. Rao Nagar, Secunderabad, Telangana, India","Telangana, India","Andhra Pradesh, India"}', '{"Drying","Agriculture","Processing"}', 'https://innovationguild.in/innovation/home', 'Grain Shell', null, null, null, null, null, null, null, 'A. S. Rao Nagar, Secunderabad, Telangana, India', 'https://innovationguild.in/innovation/5187/mini-solar-mobile-dryer', 'Innovation Guild API does not expose organization website/email/phone', 'https://innovationguild.in/innovation/5187/mini-solar-mobile-dryer
https://innovationguild.in/innovation/4823/solar-mobile-dryer', 'Address captured from Innovation Guild. Email and phone can be enriched later through organization-contact-seed.json and admin syncs.', 17.4784775, 78.5506371, 2, 'Mini Solar Mobile Dryer Grain shell Solar Mobile Dryer (SMD2000/SMD4000) is a collapsible, tunnel type dryer with 2 ton (2000Kg)/4 ton (4000kg) drying capacity designed to protect the agricultural commodity from uneven / sudden rains during drying, and to prevent spillage and contamination damage. Drying efficiency is dependent on the solar radiation, relative humidity of the ambient air, and moisture content of concerned agricultural commodity. The Solar Mobile Dryer consists of semi-transparent cover made of UV Resistant Poly film/cross laminated film connected to the black fabric coated PVC film by a high strength zipper. Through the semi-transparent top cover, solar radiation enters the drying chamber and heats of the agricultural commodity being dried. Moisture in the commodity is evaporated and pushed by the DC Fans out from the drying chamber. The Solar Mobile Dryer SMD2000/SMD4000 drying possible even during unexpected rain conditions. It can dry grains, seeds, nuts, coffee beans, Cocoa beans, spices, oil seeds at an average drying rate of 0.5 to 1.0% per hour on grains. However, during full sunny condition drying time is about 24 hours on a moisture content reduce 28 to 14%. Grain Shell Drying A. S. Rao Nagar, Secunderabad, Telangana, India Telangana, India Solar Mobile Dryer Andhra Pradesh, India', '{"organization_name":"Grain Shell","organization_code":"GRAIN1762252229351"}'::jsonb, now(), now());
