insert into public.innovation_guild_vendors (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('M/S_A1723281227175', 'M/S APPLINNOVA', 'The Panval Rocket Stove (PRS-v5) is a natural-draft clean cookstove designed to embody the concepts explained in the previous section.', null, 'Bengaluru, Karnataka, India | Karnataka, India', null, null, 'India', '{"Bengaluru, Karnataka, India","Karnataka, India"}', '{"Smokeless Cooking","Others"}', 'https://innovationguild.in/innovation/home', 'M/S APPLINNOVA', null, null, null, null, null, null, null, 'Bengaluru, Karnataka, India', 'https://innovationguild.in/innovation/1347/panval-rocket-stove-prs-v5', 'Innovation Guild API does not expose organization website/email/phone', 'https://innovationguild.in/innovation/1347/panval-rocket-stove-prs-v5', 'Address captured from Innovation Guild. Email and phone can be enriched later through organization-contact-seed.json and admin syncs.', 12.9715987, 77.5945627, 1, 'Panval Rocket Stove PRS-v5 A revolutionary cookstove product that makes domestic cooking easy, safe and virtually FREE of fuel costs in rural India. The PRS-v5 is a smoke-free & economical biomass cookstove that can cook full family meals using small twigs.
With the PRS-v5, all you have to do is gather a few fallen twigs and you are ready to cook your family meal in the comfort of a smoke-free kitchen!
The PRS-v5 stove is almost a dream-come-true for India''s villages and small towns. Bringing ultra Clean, almost cost-Free domestic cooking to Rural and semi-Urban India, it promises to permanently liberate the masses from their dependence on increasingly costly petro fuels like LPG.
The P&#257;nval Rocket Stove (PRS-v5), if used en-masse, will not only make cooking cleaner and safer for India''s masses but it will also halt the rapid degradation and destruction of India''s forests which are being recklessly hacked for firewood that is being wastefully used in smoky and hazardous cooking fires all over the country. M/S APPLINNOVA Smokeless Cooking Bengaluru, Karnataka, India Karnataka, India', '{"organization_name":"M/S APPLINNOVA","organization_code":"M/S_A1723281227175"}'::jsonb, now(), now());
