insert into public.innovation_guild_vendors (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('ROWER1758615519371', 'Rower India', 'We at Rower India, focus on building farm mechanisation products mainly focused at small and marginal farmers to help them do farming efficiently and without the need for skilled labour. Currently we have machines built for sowing of vegetable crops such as carrot, beetroot, radish, corn, cotton, groundnut etc.', null, 'Chennai, Tamil Nadu, India | Andhra Pradesh, India | Tamil Nadu, India | Telangana, India | Karnataka, India', null, null, 'India', '{"Chennai, Tamil Nadu, India","Andhra Pradesh, India","Tamil Nadu, India","Telangana, India","Karnataka, India"}', '{"Sowing","Agriculture","Production"}', 'https://innovationguild.in/innovation/home', 'Rower India', null, null, null, null, null, null, null, 'Chennai, Tamil Nadu, India', 'https://innovationguild.in/innovation/3781/manual-carrot-seeding-machine', 'Innovation Guild API does not expose organization website/email/phone', 'https://innovationguild.in/innovation/3781/manual-carrot-seeding-machine', 'Address captured from Innovation Guild. Email and phone can be enriched later through organization-contact-seed.json and admin syncs.', 13.0843007, 80.2704622, 1, 'Manual Carrot Seeding Machine This is a manual 4 row push type carrot seeding machine. This machine is designed to efficiently seed carrot vegetable by saving seed consumption, minimizing labour and saving time to cultivate. It is operated by one person at the back who pushes the machine, as the machine is pushed on the soil, a plough cuts the soil according to an adjustable depth and then a roller system disperses the seeds in regular intervals and this is then covered by the rear wheel. The machine weighs 11 kg and is made of steel and powder coated for a durability. It comes with a 1 year warranty on manufacturing defects. Rower India Sowing Chennai, Tamil Nadu, India Andhra Pradesh, India Tamil Nadu, India Telangana, India Karnataka, India', '{"organization_name":"Rower India","organization_code":"ROWER1758615519371"}'::jsonb, now(), now());
