insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('5072', 'UNG_A1772518016839', 'UNG Agros', 'Cultirake', 'The Cultirake is a multi-purpose agricultural hand tool designed for soil loosening, weed removal, and surface leveling. It combines the functionality of a cultivator and a rake, making it highly efficient for inter-row cultivation and seedbed preparation.
Manufactured with high-quality carbon steel tines, the Cultirake ensures durability, strength, and long-lasting performance in farm and garden conditions. Its sharp and sturdy teeth penetrate the soil easily, breaking clods and removing weeds from the root level.
&#128207; General Specifications
Strong Carbon Steel Tines
Multiple Teeth Design (3)
