insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('1351', 'MITTI1723444744009', 'Mitti Dhan', 'Efficient and Low Cost Weeding Tool', 'Weeding tools are either machine operated or a simple sickle, while using sickle it gives back and knee pain and it''s very time consuming work, Small farmers can''t afford machine tools for their small land, Tools we have designed are perfect match for the farmers need, it doesn''t require maintained, It''s light weight and durable, specially designed for all genders.', 'https://innovationguild.in/innovation/1351/efficient-and-low-cost-weeding-tool', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723444508074-Weeder_-_Hiren_Panchal.png', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723444508074-Weeder_-_Hiren_Panchal.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_design_gallery/1723444709962-Weeder_-_Hiren_Panchal.png"]'::jsonb, '["https://www.youtube.com/embed/-d5k_nSJhsw","https://www.youtube.com/embed/KQpSat7SgS0"]'::jsonb, 'Valsad, Gujarat, India | Gujarat, India', '{"Agriculture"}', '{"Production"}', '[{"key":"Year Launched","value":"2020","code":"CHANGEMAKER_META_CODE.YEAR_LAUNCHED"},{"key":"Training on Maintenance and After Sales Services","value":"yes","code":"CHANGEMAKER_META_CODE.TRAINING_ON_MAINTENANCE_AND_AFTER_SALES_SERVICES"},{"key":"Spare Parts for Product","value":"yes","code":"CHANGEMAKER_META_CODE.SPARE_PARTS_FOR_PRODUCT"},{"key":"Demo Installations","value":"yes","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Engine Details","value":"Test","code":"CHANGEMAKER_META_CODE.ENGINE_DETAILS"},{"key":"Opportunity Suppor