insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('4330', 'AGRIL1764931859632', 'Agrilectric Private Limited', 'Electric Brush Cutter (e-Brush Cutter)', 'The e-Brush Cutter is a multi-purpose electric agricultural implement designed to replace conventional petrol engine brush cutters with a cleaner, quieter, and more economical solution. It is suitable for daily farm operations including harvesting, weeding, pruning, raking, and landscaping.
Technical Specifications:
Rated Power: 2 kW electric motor
Maximum Speed: 6500 RPM
Battery Pack: 48 V, 15 Ah
Backup Time: Up to 180 minutes (depending on attachment)
Charging Time: 2 hours (fast charger optional)
Tube Diameter: 28 mm | Shaft Diameter: 8 mm
Weight: 11.25 kg
Performance & Operations:
The system can perform all operations typically handled by engine-based brush cutters, delivering consistent power with very low vibration and near-silent operation.
Cost & Sustainability:
Operating cost of approximately &#8377;1.8 - &#8377;2 per hour
Near-zero maintenance due to absence of fuel, oil, and engine components
Zero emissions and low noise, making it environmentally friendly and safer for operators
The e-Brush Cutter is designed for small and marginal farmers seeking a reliable, low-cost, and sustainable alternative to fuel-powered farm equipment.', 'https://innovationguild.in/innovation/4330/electric-brush-cutter-e-brush-cutter', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1766398470911-WhatsApp_Image_2025-11-06_at_22.59.34_fabee34d.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1766398470911-WhatsApp_Image_2025-11-06_at_22.59.34_fabee34d.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_resources/1766406524921-EBC_manual_draft_2.0_%281%29.pdf","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1766406728852-WhatsApp_Image_2025-09-18_at_15.47.18_bad28716.jpg"]'::jsonb, '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1766398505865-Electric_Brush_Cutter.mp41080p1763549780152_All_Video_Downloader_%281%29.mp4"]'::jsonb, 'No.94, Lakshmanappa Layout, Silvepura Post Hessaraghatta Hobli, Yelahanka Taluk North, Bengaluru, Karnataka 560090, India | Karnataka, India', '{"Agriculture"}', '{"Maintenance and management"}', '[{"key":"Weather Conditions","value":"Works efficiently in dry and moderately moist field conditions. Performs best when soil is not fully water-logged. Electric drive ensures smooth operation in hot and humid climates with minimal performance loss. No fuel-evaporation issues during summer and no cold-start problems in winter.","code":"CHANGEMAKER_META_CODE.WEATHER_CONDITIONS"},{"key":"Suitable Crops","value":"Paddy, Wheat, Arecanut, Coconut, Millets, Maize, Groundnut, Vegetables (Tomato, Chilli, Brinjal, Beans), Plantation crops, Horticulture crops, Inter-row crops, Fodder grass, Dry leaves & mulch residue, Paddy straw, Coconut fronds.","code":"CHANGEMAKER_META_CODE.SUITABLE_CROPS"},{"key":"Demo Installations","value":"yes","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Imported Parts","value":"N