insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('3837', 'TRIDE1759830235473', 'Trident Agri Ventures Pvt Ltd', 'Four Row handpush seeder', 'More rows, More efficiency. Maximum flexibility - Designed for speed and accuracy, this four-row seeder is ideal for farmers looking to cover more ground in less time without sacrificing planting precision. With customizable spacing, depth and gear control. it''s suited for a wide variety of seeds and field conditions.
Material - Sturdy ABS, Iron and Plastic for Durability.
Adjustable planting - 0-50 cm for Flexible crop layout.
Adjustable planting depth - 1-4 cm to suit different seed types.
Seed roller - 12 High-Precision rollers for uniform multi-row planting.
