insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('4873', 'NAVAR1723445963240', 'NAVARITI INNOVATION PVT LTD', 'HELIOT Automatic Weather Station – AI Powered SMART ENVIRO SENSE', 'HELIOT SMART ENVIRO SENSE is an IoT-enabled, solar-powered Automatic Weather Station (AWS) designed for village-level microclimate monitoring and climate-smart agriculture. Developed by Navariti Innovation Pvt Ltd under the HELIOT.AI brand, this solution provides real-time weather data, localized 8-day forecasts, AI-based crop advisory, irrigation recommendations, fertilizer guidance, and pest & disease alerts.
The system measures key weather parameters including temperature, humidity, atmospheric pressure, rainfall, wind speed & direction, solar radiation, and other customizable sensors based on project requirements. It is built for deployment in plains, hilly terrains, tribal areas, high-value crop clusters, and rural communities.
The "One Village - One Weather Station" model ensures accurate village-level data instead of district-level approximations. Farmers receive crop-stage specific advisory through the HELIOT analytics platform via real-time dashboards and mobile access.
Key Benefits:
10 - 20% Yield Increase
20 - 40% Water Savings
Improved fertilizer efficiency
Early pest & disease warning
Climate risk preparedness
Better crop planning & harvest scheduling
The system supports FPOs, NGOs, CSR projects, agricultural universities, and rural development agencies in driving climate resilience and sustainable agriculture.
HELIOT AWS is currently deployed across multiple Indian states including Telangana, Maharashtra, Andhra Pradesh, Karnataka, Rajasthan, and others, enabling data-driven decision making for small and marginal farmers.', 'https://innovationguild.in/innovation/4873/heliot-automatic-weather-station-ai-powered-smart-enviro-sense', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144675199-AWS_Vijayawada.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144675199-AWS_Vijayawada.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_resources/1771146365005-HELIOT_Weather_Station_Brochure.pdf","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144814499-Weather_Station_Image.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144777073-6.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144776076-weather_station_6.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144776726-13.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144814160-AWS_-_Nagpur_Ambuja.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144814547-AWS_Nagpur.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144814421-AWS_Mulkanoor.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771144814461-Weather_Station_field_1.jpg","https://www.bing.com/ck/a?!&&p=f7a281e2ae20674b058390baf68a9c14294fc3547b43367afab8f86b42b68410JmltdHM9MTc3MTE0NDg1Ng&ptn=3&fclid=0b173cf8-0a4a-11f1-8c86-bff2f1bf6514&"]'::jsonb, '[]'::jsonb, 'Balanagar, Hyderabad, Telangana, India | Maharashtra, India | Odisha, India | Andhra Pradesh, India | Karnataka, India | Telangana, India | Rajasthan, India | Tamil Nadu, India', '{"Agriculture"}', '{"Maintenance and management"}', '[{"key":"Number of U