insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('4874', 'NAVAR1723445963240', 'NAVARITI INNOVATION PVT LTD', 'HELIOT Smart Irrigation Controller (Motor Control System)', 'HELIOT Smart Irrigation Controller is an AI and IoT-enabled motor automation system designed to optimize irrigation management for farmers. Developed by Navariti Innovation Pvt Ltd under the HELIOT.AI brand, the system allows farmers to operate irrigation pumps and valves remotely using a mobile application.
The controller enables automatic ON/OFF operation, timer-based scheduling, soil moisture-based automation, and real-time motor monitoring. It includes protection features such as phase failure detection, dry-run protection, and voltage fluctuation safeguards to ensure motor safety and long operational life.
Farmers can operate motors from anywhere, reducing repeated farm visits and saving time, water, and electricity. The system integrates with HELIOT''s weather station and advisory platform to provide irrigation recommendations based on crop stage, weather forecast, and soil conditions.
Key Features:
Remote motor ON/OFF via mobile app
Timer & scheduling mode
Manual & automatic mode
Phase failure detection
Dry-run protection
Voltage fluctuation protection
Soil moisture-based irrigation (optional)
Real-time motor & power status monitoring
Water & electricity savings (20 - 40%)
User-friendly mobile app interface
Impact:
Reduced water wastage
Reduced electricity consumption
Improved crop consistency
Reduced labor & travel cost
Better irrigation scheduling
Increased productivity
The solution is suitable for small, marginal, and commercial farmers growing field crops, horticulture crops, and plantations.', 'https://innovationguild.in/innovation/4874/heliot-smart-irrigation-controller-motor-control-system', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771146956119-HELIOT_MC_field.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771146956119-HELIOT_MC_field.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_resources/1771147315616-Smart_Irrigation_Controller_Installations_%26_Testimonials_%281%29.pdf","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771147058308-HELIOT_MC_Installation_field_2.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1771147080792-Smart_Irrigation_Controller_Image.jpg"]'::jsonb, '[]'::jsonb, 'Balanagar, Hyderabad, Telangana, India | Karnataka, India | Telangana, India | Maharashtra, India | Andhra Pradesh, India', '{"Agriculture"}', '{"Maintenance and management"}', '[{"key":"Number of Unit Installed","value":"50+","code":"CHANGEMAKER_META_CODE.NUM_OF_UNITS_INSTALLED"},{"key":"Weather Conditions","value":"The system operates reliably under high temperature, humid conditions, and monsoon environments. Weatherproof enclosure protects internal circuitry. Integrated with HELIOT weather data for improved irrigation decisions during extreme heat, rainfall, or drought conditions.","code":"CHANGEMAKER_META_CODE.WEATHER_CONDITIONS"},{"key":"Financing Support","value":"open","code":"CHANGEMAKER_META_CODE.FINANCING_SUPPORT"},{"key":"Demo Installations","value":"yes","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Year Launched","value":"2021","code":"CHANGEMAKER_META_CODE.YEAR_LAUNCHED"},{"key":"Product Weight","value":"Approx. 2.5 – 4 kg","code":"CHANGEMAKER_META_CODE.PRODUCT_WEIGHT"},{"key":"Suitable Soil","value":"Black soil, Red soil, Sandy loam, Clay loam, Alluvial so