insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('4241', '4TH_P1764678674095', '4th Phase Water Technologies Pvt Ltd - Jiva Water', 'Jiva Water Farm Device Vipasa - Better Water for Higher Yield and Soil Fertility', 'Vipasa is a non-electric water device, ideal for small agricultural lands, poultry, and cattle farms, designed to improve water efficiency and absorption by roots, stems, and plants. It enhances soil fertility, reduces soil salinity, and boosts crop nutritional value. With better water efficiency, it supports higher yields, faster crop cycles, and improved overall farm productivity. For poultry and cattle, consistent water quality helps maintain optimal health for livestock and supports better productivity. Built with premium-grade stainless steel, Vipasa is durable, low-maintenance, and easy to install for efficient farm irrigation.', 'https://innovationguild.in/innovation/4241/jiva-water-farm-device-vipasa-better-water-for-higher-yield-and-soil-fertility', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1764768914968-Jiva_edited03.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1764768914968-Jiva_edited03.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1764769007548-Untitled_design.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1764770415329-JIVA_Water_Partnership_Deck.pdf.jpg"]'::jsonb, '["https://www.youtube.com/embed/tKol4n527-4"]'::jsonb, '4th Phase Water Technologies Pvt Ltd - Jiva Water, 12/2, 2nd Main Rd, below SBI, 7th Block, Jayanagar, Bengaluru, Karnataka 560070, India | Kerala, India | Maharashtra, India | T