AFTER_SALES_SERVICES"},{"key":"Power Source","value":"Manual","code":"CHANGEMAKER_META_CODE.POWER_SOURCE"},{"key":"Other Conditions","value":"None","code":"CHANGEMAKER_META_CODE.OTHER_CONDITIONS"},{"key":"Number of Unit Installed","value":"Not listed","code":"CHANGEMAKER_META_CODE.NUM_OF_UNITS_INSTALLED"},{"key":"Weather Conditions","value":"Suitable for all weather","code":"CHANGEMAKER_META_CODE.WEATHER_CONDITIONS"},{"key":"Demo Installations","value":"yes","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Performance Parameters","value":"Crop nutrific value, Soil fertility, Yield etc.","code":"CHANGEMAKER_META_CODE.PERFORMANCE_PARAMETERS"}],"created_at":"2025-12-03T19:36:24.678+05:30"}'::jsonb, now(), now());
insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('3781', 'ROWER1758615519371', 'Rower India', 'Manual Carrot Seeding Machine', 'This is a manual 4 row push type carrot seeding machine. This machine is designed to efficiently seed carrot vegetable by saving seed consumption, minimizing labour and saving time to cultivate. It is operated by one person at the back who pushes the machine, as the machine is pushed on the soil, a plough cuts the soil according to an adjustable depth and then a roller system disperses the seeds in regular intervals and this is then covered by the rear wheel. The machine weighs 11 kg and is made of steel and powder coated for a durability. It comes with a 1 year warranty on manufacturing defects.', 'https://innovationguild.in/innovation/3781/manual-carrot-seeding-machine', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1758640238986-333333.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1758640238986-333333.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_resources/1758639954173-Product_Manual_-_MICRON.pdf","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1758640236340-4444.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1758640236898-11111.jpg"]'::jsonb, '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1758640246750-22222.mp4"]'::jsonb, 'Chennai, Tamil Nadu, India | Andhra Pradesh, India | Tamil Nadu, India | Telangana, India | Karnataka, India', '{"Agriculture"}', '{"Production"}', '[{"key":"Other Conditions","value":"In tight spaces and terraced plots","code"