insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('1354', 'AEDAA1723446285869', 'AEDAA EQUIPMENT', 'Mini Solar Insect trap', 'Introducing our Eco-Friendly Solar-Powered Pest Controller - Perfect for Diverse Crops and Go-downs
Our innovative pest control solution harnesses the power of solar energy, making it an environmentally friendly choice for farmers and warehouse managers. Designed to suit a variety of crops, this device is ideal for use in go-downs and fields alike.
Key Features:
Solar-Powered Efficiency:- Utilizes sustainable solar energy, ensuring continuous operation without the need for external power sources. This feature not only saves energy but also reduces operational costs.
Advanced UV Attraction Technology:- Equipped with slightly visible UV light, our pest controller expertly lures flies and other insects. The pests are then efficiently trapped in the soap and oil water tank positioned beneath the light. This method is safe, non-toxic, and highly effective.
Automatic and User-Friendly:- Designed to operate automatically, this pest controller requires minimal human intervention, making it a convenient solution for busy farmers and warehouse managers.
Natural Crop Protection:- By attracting and eliminating pests, our device naturally protects crops from insect damage. This reduces the reliance on harmful chemicals and pesticides, promoting healthier crop growth and a safer environment.
Cost-Effective:- With its solar-powered design and automatic operation, this pest controller significantly reduces manpower expenses and eliminates the need for electrical power, making it a cost-effective solution for pest management.
Ideal for a range of agricultural and storage settings, our Solar-Powered Pest Controller is an innovative step towards sustainable and efficient pest management.', 'https://innovationguild.in/innovation/1354/mini-solar-insect-trap', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723448379369-mini_trap_1_-_AEDAA_equipments.jpeg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723448379369-mini_trap_1_-_AEDAA_equipments.jpeg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_design_gallery/1723448436579-mini_trap_1_-_AEDAA_equipments.jpeg"]'::jsonb, '["https://www.youtube.com/embed/1zVMWafaXSo","https://www.youtube.com/embed/E38S7QqNw5o","https://www.youtube.com/embed/E38S7QqNw5o"]'::jsonb, 'Gattu, Andhra Pradesh 517352, India | Rajasthan, India', '{"Agriculture"}', '{"Maintenance and management"}', '[{"key":"Performance Parameters","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PERFORMANCE_PARAMETERS"},{"key":"Maximum cost of product","value":"2000","code":"CHANGEMAKER_META_CODE.MAXIMUM_COST_OF_PRODUCT"},{"key":"Other Conditions","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.OTHER_CONDITIONS"},{"key":"Power Source","value":"Electrical","code":"CHANGEMAKER_META_CODE.POWER_SOURCE"},{"key":"Product Weight","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PRODUCT_WEIGHT"},{"key":"Training on Maintenance and After Sales Services","value":"yes","code":"CHANGEMAKER_META_CODE.TRAINING_ON_MAINTENANCE_AND_AFTER_SALES_SERVICES"},{"key":"Product Dimensions","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PRODUCT_DIMENSIONS"},{"key":"Demo Installations","value":"yes","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Opportunity Stage","value":"POC","code":"CHANGEMAKER_META_CODE.OPPORTUNITY_STAGE"},{"key":"Weather Conditions","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.WEATHER_CONDITIONS"},{"key":"Network Distributors","value":"none","code":"CHANGEMAKER_META_CODE.NETWORK_DISTRIBUTORS"},{"key":"Product Attachments","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PRODUCT_ATTACHMENTS"},{"key":"Number of Unit Installed","value":"1","code":"CHANGEMAKER_META_CODE.NUM_OF_UNITS_INSTALLED"},{"key":"Imported Parts","value":"No","code":"CHANGEMAKER_META_CODE.IMPORTED_PARTS"},{"key":"Suitable Soil","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.SUITABLE_SOIL"},{"key":"Opportunity Support","value":"Not listed","code":"CHANGEMAKER_META_CODE.OPPORTUNITY_SUPPORT_FROM_PLATFORM"},{"key":"Engine Details","value":"Test- Dummy 1","code":"CHANGEMAKER_META_CODE.ENGINE_DETAILS"},{"key":"Spare Parts for Product","value":"yes","code":"CHANGEMAKER_META_CODE.SPARE_PARTS_FOR_PRODUCT"},{"key":"Technical Training","value":"yes","code":"CHANGEMAKER_META_CODE.TECHNICAL_TRAINING"},{"key":"Minimum cost of product","value":"1800","code":"CHANGEMAKER_META_CODE.MINIMUM_COST_OF_PRODUCT"},{"key":"Suitable Terrains","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.SUITABLE_TERRAINS"},{"key":"Suitable Crops","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.SUITABLE_CROPS"},{"key":"Financing Support","value":"na","code":"CHANGEMAKER_META_CODE.FINANCING_SUPPORT"},{"key":"Year Launched","value":"2022","code":"CHANGEMAKER_META_CODE.YEAR_LAUNCHED"}]'::jsonb, '{"Insects Trap"}', 'Mini Solar Insect trap Introducing our Eco-Friendly Solar-Powered Pest Controller - Perfect for Diverse Crops and Go-downs
Our innovative pest control solution harnesses the power of solar energy, making it an environmentally friendly choice for farmers and warehouse managers. Designed to suit a variety of crops, this device is ideal for use in go-downs and fields alike.
Key Features:
Solar-Powered Efficiency:- Utilizes sustainable solar energy, ensuring continuous operation without the need for external power sources. This feature not only saves energy but also reduces operational costs.
Advanced UV Attraction Technology:- Equipped with slightly visible UV light, our pest controller expertly lures flies and other insects. The pests are then efficiently trapped in the soap and oil water tank positioned beneath the light. This method is safe, non-toxic, and highly effective.
Automatic and User-Friendly:- Designed to operate automatically, this pest controller requires minimal human intervention, making it a convenient solution for busy farmers and warehouse managers.
Natural Crop Protection:- By attracting and eliminating pests, our device naturally protects crops from insect damage. This reduces the reliance on harmful chemicals and pesticides, promoting healthier crop growth and a safer environment.
Cost-Effective:- With its solar-powered design and automatic operation, this pest controller significantly reduces manpower expenses and eliminates the need for electrical power, making it a cost-effective solution for pest management.
Ideal for a range of agricultural and storage settings, our Solar-Powered Pest Controller is an innovative step towards sustainable and efficient pest management. AEDAA EQUIPMENT Insects Trap Agriculture Maintenance and management Gattu, Andhra Pradesh 517352, India Rajasthan, India Performance Parameters Test- Dummy1 Maximum cost of product 2000 Other Conditions Test- Dummy1 Power Source Electrical Product Weight Test- Dummy1 Training on Maintenance and After Sales Services yes Product Dimensions Test- Dummy1 Demo Installations yes Opportunity Stage POC Weather Conditions Test- Dummy1 Network Distributors none Product Attachments Test- Dummy1 Number of Unit Installed 1 Imported Parts No Suitable Soil Test- Dummy1 Opportunity Support Not listed Engine Details Test- Dummy 1 Spare Parts for Product yes Technical Training yes Minimum cost of product 1800 Suitable Terrains Test- Dummy1 Suitable Crops Test- Dummy1 Financing Support na Year Launched 2022', '{"innovation_id":"1354","slug":"mini-solar-insect-trap","title":"Mini Solar Insect trap","description":"Introducing our Eco-Friendly Solar-Powered Pest Controller - Perfect for Diverse Crops and Go-downs\nOur innovative pest control solution harnesses the power of solar energy, making it an environmentally friendly choice for farmers and warehouse managers. Designed to suit a variety of crops, this device is ideal for use in go-downs and fields alike.\nKey Features:\nSolar-Powered Efficiency:- Utilizes sustainable solar energy, ensuring continuous operation without the need for external power sources. This feature not only saves energy but also reduces operational costs.\nAdvanced UV Attraction Technology:- Equipped with slightly visible UV light, our pest controller expertly lures flies and other insects. The pests are then efficiently trapped in the soap and oil water tank positioned beneath the light. This method is safe, non-toxic, and highly effective.\nAutomatic and User-Friendly:- Designed to operate automatically, this pest controller requires minimal human intervention, making it a convenient solution for busy farmers and warehouse managers.\nNatural Crop Protection:- By attracting and eliminating pests, our device naturally protects crops from insect damage. This reduces the reliance on harmful chemicals and pesticides, promoting healthier crop growth and a safer environment.\nCost-Effective:- With its solar-powered design and automatic operation, this pest controller significantly reduces manpower expenses and eliminates the need for electrical power, making it a cost-effective solution for pest management.\nIdeal for a range of agricultural and storage settings, our Solar-Powered Pest Controller is an innovative step towards sustainable and efficient pest management.","detail_url":"https://innovationguild.in/innovation/1354/mini-solar-insect-trap","organization_name":"AEDAA EQUIPMENT","organization_code":"AEDAA1723446285869","organization_description":"At AEDAA Equipments, we are dedicated to transforming the agricultural landscape through technology and AI. Our goal is to enhance crop yield, promote sustainable farming, and make high-tech farming accessible to modern farmers. We specialize in providing crop-specific water optimization, fertigation automation, and low-maintenance motor controllers, alongside advanced pest prediction and control solutions.","tenant_name":"Innovation Guild","category_codes":["OPPORTUNITY_CATEGORY_INNOVATORS.AGRI"],"categories":["Agriculture"],"subcategory_codes":["OPPORTUNITY_SUB_CATEGORY_INNOVATORS.MAINTENANCE_AND_MANAGEMENT"],"subcategories":["Maintenance and management"],"tag_codes":[],"tags":["Insects Trap"],"stage":"POC","minimum_cost":"1800","maximum_cost":"2000","power_source":"Electrical","year_launched":"2022","primary_location":"Gattu, Andhra Pradesh 517352, India","location_text":"Gattu, Andhra Pradesh 517352, India | Rajasthan, India","locations":["Gattu, Andhra Pradesh 517352, India","Rajasthan, India"],"latitude":13.6610203,"longitude":78.33319279999999,"cover_image_url":"https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723448379369-mini_trap_1_-_AEDAA_equipments.jpeg","image_urls":["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723448379369-mini_trap_1_-_AEDAA_equipments.jpeg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_design_gallery/1723448436579-mini_trap_1_-_AEDAA_equipments.jpeg"],"videos":[{"source_url":"https://www.youtube.com/shorts/1zVMWafaXSo","embed_url":"https://www.youtube.com/embed/1zVMWafaXSo","platform":"youtube"},{"source_url":"https://www.youtube.com/shorts/E38S7QqNw5o","embed_url":"https://www.youtube.com/embed/E38S7QqNw5o","platform":"youtube"},{"source_url":"https://www.youtube.com/shorts/E38S7QqNw5o","embed_url":"https://www.youtube.com/embed/E38S7QqNw5o","platform":"youtube"}],"specifications":[{"key":"Performance Parameters","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PERFORMANCE_PARAMETERS"},{"key":"Maximum cost of product","value":"2000","code":"CHANGEMAKER_META_CODE.MAXIMUM_COST_OF_PRODUCT"},{"key":"Other Conditions","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.OTHER_CONDITIONS"},{"key":"Power Source","value":"Electrical","code":"CHANGEMAKER_META_CODE.POWER_SOURCE"},{"key":"Product Weight","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PRODUCT_WEIGHT"},{"key":"Training on Maintenance and After Sales Services","value":"yes","code":"CHANGEMAKER_META_CODE.TRAINING_ON_MAINTENANCE_AND_AFTER_SALES_SERVICES"},{"key":"Product Dimensions","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.PRODUCT_DIMENSIONS"},{"key":"Demo Installations","value":"yes","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Opportunity Stage","value":"POC","code":"CHANGEMAKER_META_CODE.OPPORTUNITY_STAGE"},{"key":"Weather Conditions","value":"Test- Dummy1","code":"CHANGEMAKER_META_CODE.WEATHER_CONDITIONS"},{"key":"Network Distributors","value":"none","code":"CHANGEMAKER_META_CO