insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('1347', 'M/S_A1723281227175', 'M/S APPLINNOVA', 'Panval Rocket Stove PRS-v5', 'A revolutionary cookstove product that makes domestic cooking easy, safe and virtually FREE of fuel costs in rural India. The PRS-v5 is a smoke-free & economical biomass cookstove that can cook full family meals using small twigs.
With the PRS-v5, all you have to do is gather a few fallen twigs and you are ready to cook your family meal in the comfort of a smoke-free kitchen!
The PRS-v5 stove is almost a dream-come-true for India''s villages and small towns. Bringing ultra Clean, almost cost-Free domestic cooking to Rural and semi-Urban India, it promises to permanently liberate the masses from their dependence on increasingly costly petro fuels like LPG.
The P&#257;nval Rocket Stove (PRS-v5), if used en-masse, will not only make cooking cleaner and safer for India''s masses but it will also halt the rapid degradation and destruction of India''s forests which are being recklessly hacked for firewood that is being wastefully used in smoky and hazardous cooking fires all over the country.', 'https://innovationguild.in/innovation/1347/panval-rocket-stove-prs-v5', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723281269128-Panval_Rocket_Stove_PRS-v5.png', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723281269128-Panval_Rocket_Stove_PRS-v5.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_design_gallery/1723281480435-07-web.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_design_gallery/1723281480436-12-web-cropped.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723281461228-07-web.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_design_gallery/1723281480392-15-web-595x705.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723281461290-12-web-cropped.png","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1723281461322-15-web-595x705.png"]'::jsonb, '["https://www.youtube.com/embed/pBcOiMa-owE","https://www.youtube.com/embed/c8Cjey-QmfM","https://www.youtube.com/embed/qtAbSTFMrMI"]'::jsonb, 'Bengaluru, Karnataka, India | Karnataka, India', '{"Others"}', '{"Others"}', '[{"key":"Engine Details","value":"Test","code":"CHANGEMAKER_META_CODE.ENGINE_DETAILS"},{"key":"Spare Parts for Product","value":"yes","code":"CHANGEMAKER_META_CODE.SPARE_PARTS_FOR_PRODUCT"},{"key":"Imported Parts","value":"No","code":"CHANGEMAKER_META_CODE.IMPORTED_PARTS"},{"key":"Product Dimensions","value":"Test","code":"CHANGEMAKER_META_CODE.PRODUCT_DIMENSIONS"},{"key":"Suitable Crops","value":"Test","code":"CHANGEMAKER_META_CODE.SUITA