insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('5236', 'KATID1773664922264', 'Katidhan', 'PB v 3.0 Solar powered Autonomous wild animal deterrent device', 'Parabraksh, a Solar-Powered Wild Animal Deterrent System, is an innovative solution designed&#10;to protect farmlands and sensitive areas from animal intrusions. Using advanced solar technology&#10;
and an illusion of moving flashing LED lights, Parabraksh creates a psychological barrier that&#10;
keeps animals away without causing them harm. Its eco-friendly and low-maintenance design&#10;
makes it ideal for farmers and rural communities.', 'https://innovationguild.in/innovation/5236/pb-v-30-solar-powered-autonomous-wild-animal-deterrent-device', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1775301722182-PB_v_3.0.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1775301722182-PB_v_3.0.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_resources/1775301226130-Parabraksh_Manual_3.0v.pdf","https://www.youtube.com/playlist?list=PLr7ikCdLe-GEx_Z_uYFwXrosRCHPfmCDy","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1775301972344-installation_guide_parabraksh.jpg"]'::jsonb, '["https://www.youtube.com/embed/II73P7PROdk","https://www.youtube.com/embed/efFPlr9189k","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1775301966054-WhatsApp_Video_2026-04-04_at_4.55.35_PM.mp4","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1775302114880-VID-20250903-WA0003_%281%29.mp4","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1775302547380-Parabraksh_Installation_Video_%282%29.mp4"]'::jsonb, 'Bengaluru, Karnataka, India | Karnataka, India', '{"Agriculture"}', '{"Maintenance and management"}', '[{"key":"Power Source","value":"Manual","code":"CHANGEMAKER_META_CODE.POWER_SOURCE"},{"key":"Number of Unit Installed","value":"3100","code":"CHANGEMAKER_META_CODE.NUM_OF_UNITS_INSTALLED"},{"key":"Financing Support","value":"open","code":"CHANGEMAKER_META_CODE.FINANCING_SUPPORT"},{"key":"Technical Training","value":"yes","code":"CHANGEMAKER_META_CODE.TECHNICAL_TRAINING"},{"key":"Performance Parameters","value":"Lighting System: 4 powerful LED lights flashing in a random, unpredictable pattern to prevent habituation by animals.Protection Area: Provides 360 degree coverage from a single unit, typically mounted on poles. Power Source: Solar-powered with lithium batteries; includes a Dual Charging mechanism (Solar and Micro-USB).Automation: Automatic, sensor-driven switching (turns ON at night, OFF during the day).Environmental Resistance: Designed to be all-weather resistant.Targeted Wildlife: Proven effectiveness against elephants, nilgai, wild boar, deer, tigers, leopards, bears, etc.","code":"CHANGEMAKER_META_CODE.PERFORMANCE_PARAMETERS"},{"key":"Imported Parts","value":"NA","code":"CHANGEMAKER_META_CODE.IMPORTED_PARTS"},{"key":"Network Distributors","value":"few","code":"CHANGEMAKER_META_CODE.NETWORK_DISTRIBUTORS"},{"key":"Suitable Terrains","value":"All terrains","code":"CHANGEMAKER_META_CODE.SUITABLE_TERRAINS"},{"key":"Suitable Soil","value":"All soil types","code":"CHANGEMAKER_META_CODE.SUITABLE_SOIL"},{"key":"Engine Details","value":"Solar-Powered, Wattage: 10W,Capacity: 96.2Wh ,Voltage: 3.7V","code":"CHANGEMAKER_META_CODE.ENGINE_DETAILS"},{"key":"Product Attachments","value":"Solar Panel-Type: Mono crystaine/ Poly crystalline solar panel ,Wattage: 10W","code":"CHANGEMAKER_META_CODE.PRODUCT_ATTACHMENTS"},{"key":"Demo Installations","value":"no","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Maximum cost of product","value":"17500","code":"CHANGEMAKER_META_CODE.MAXIMUM_COST_OF_PRODUCT"},{"key":"Minimum cost of product","value":"16500","code":"CHANGEMAKER_META_CODE.MINIMUM_COST_OF_PRODUCT"},{"key":"Other Conditions","value":"Cleaning the Solar Panel: Wipe the solar panel with a damp cloth regularly to remove dust and debris for efficient charging. Inspecting the Device: Periodically check the device for proper mounting on a regular basis","code":"CHANGEMAKER_META_CODE.OTHER_CONDITIONS"},{"key":"Spare Parts for Product","value":"yes","code":"CHANGEMAKER_META_CODE.SPARE_PARTS_FOR_PRODUCT"},{"key":"Training on Maintenance and After Sales Services","value":"yes","code":"CHANGEMAKER_META_CODE.TRAINING_ON_MAINTENANCE_AND_AFTER_SALES_SERVICES"},{"key":"Opportunity Stage","value":"Sales","code":"CHANGEMAKER_META_CODE.OPPORTUNITY_STAGE"},{"key":"Year Launched","value":"2017","code":"CHANGEMAKER_META_CODE.YEAR_LAUNCHED"},{"key":"Product Weight","value":"3 kg","code":"CHANGEMAKER_META_CODE.PRODUCT_WEIGHT"},{"key":"Weather Conditions","value":"Functions in all weather conditions","code":"CHANGEMAKER_META_CODE.WEATHER_CONDITIONS"},{"key":"Suitable Crops","value":"All crops","code":"CHANGEMAKER_META_CODE.SUITABLE_CROPS"},{"key":"Product Dimensions","value":"350mm X 240mm X 180mm","code":"CHANGEMAKER_META_CODE.PRODUCT_DIMENSIONS"}]'::jsonb, '{}', 'PB v 3.0 Solar powered Autonomous wild animal deterrent device Parabraksh, a Solar-Powered Wild Animal Deterrent System, is an innovative solution designed&#10;to protect farmlands and sensitive areas from animal intrusions. Using advanced solar technology&#10;
and an illusion of moving flashing LED lights, Parabraksh creates a psychological barrier that&#10;
keeps animals away without causing them harm. Its eco-friendly and low-maintenance design&#10;
makes it ideal for farmers and rural communities. Katidhan Agriculture Maintenance and management Bengaluru, Karnataka, India Karnataka, India Power Source Manual Number of Unit Installed 3100 Financing Support open Technical Training yes Performance Parameters Lighting System: 4 powerful LED lights flashing in a random, unpredictable pattern to prevent habituation by animals.Protection Area: Provides 360 degree coverage from a single unit, typically mounted on poles. Power Source: Solar-powered with lithium batteries; includes a Dual Charging mechanism (Solar and Micro-USB).Automation: Automatic, sensor-driven switching (turns ON at night, OFF during the day).Environmental Resistance: Designed to be all-weather resistant.Targeted Wildlife: Proven effectiveness against elephants, nilgai, wild boar, deer, tigers, leopards, bears, etc. Imported Parts NA Network Distributors few Suitable Terrains All terrains Suitable Soil All soil types Engine Details Solar-Powered, Wattage: 10W,Capacity: 96.2Wh ,Voltage: 3.7V Product Attachments Solar Panel-Type: Mono crystaine/ Poly crystalline solar panel ,Wattage: 10W Demo Installations no Maximum cost of product 17500 Minimum cost of product 16500 Other Conditions Cleaning the Solar Panel: Wipe the solar panel with a damp cloth regularly to remove dust and debris for efficient charging. Inspecting the Device: Periodically check the device for proper mounting on a regular basis Spare Parts for Product yes Training on Maintenance and After Sales Services yes Opportunity Stage Sales Year Launched 2017 Product Weight 3 kg Weather Conditions Functions in all weather conditions Suitable Crops All crops Product Dimensions 350mm X 240mm X 180mm', '{"innovation_id":"5236","slug":"pb-v-30-solar-powered-autonomous-wild-animal-deterrent-device","title":"PB v 3.0 Solar powered Autonomous wild animal deterrent device","description":"Parabraksh, a Solar-Powered Wild Animal Deterrent System, is an innovative solution designed&#10;to protect farmlands and sensitive areas from animal intrusions. Using advanced solar technology&#10;\nand an illusion of moving flashing LED lights, Parabraksh creates a psychological barrier that&#10;\nkeeps animals away without causing them harm. Its eco-friendly and low-maintenance design&#10;\nmakes it ideal for farmers and rural communities.","detail_url":"https://innovationguild.in/innovation/5236/pb-v-30-solar-powered-autonomous-wild-animal-deterrent-device","organization_name":"Katidhan","organization_code":"KATID1773664922264","organization_description":"Katidhan was started by a group of engineers, designers and more importantly problem solvers to address some of the most adverse challenges faced in our surroundings through significant technological processes and solutions. These solutions are designed to be holistic in nature thus ensuring their longevity and support to address the challenges. The problems that are chosen would often tend to be complex in nature with our team moving through the process of Define, Research, Ideate, Prototype, Test, Build, Scale and Redefine. We believe in addressing the problem in real time keeping the future in view, this often involves designing solutions that often have a mix of hardware engineering with deep tech understanding of solutions. Our focus is to address complex problems with simple Design Engineered Solutions. These solutions create a glorious impact that potentially change the world for the better.We are committed towards creating a harmony between humans and wildlife to reduce losses on either side with some crazy tech based innovations","tenant_name":"Innovation Guild","category_codes":["OPPORTUNITY_CATEGORY_INNOVATORS.AGRI"],"categories":["Agriculture"],"subcategory_codes":["OPPORTUNITY_SUB_CATEGORY_INNOVATORS.MAINTENANCE_AND_MANAGEMENT"],"subcategories":["Maintenance and management"],"tag_codes":[],"tags":[],"stage":"Sales","minimum_cost":"16500","maximum_cost":"17500","power_source":"Manual","year_launched":"2017","