insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('3841', 'TRIDE1759830235473', 'Trident Agri Ventures Pvt Ltd', 'Portable manual seeder and fertilizer', 'Precision Planting balanced nutrition, Maximum efficiency - This Dual-Function manual tool allows farmer to saw seeds and apply fertilizers simultaneously. helping improve planting accuracy and crop performance in one easy operation. Ideal for row crops and vegetables, it saves labour while ensuring better spacing and nutrients placements.
Seeds output - 1 - 3 grains per drop for tailored crop need.
Planting depth - Adjustable between 3.5 - 7.8 cm for optional germination.
Number of rollers - 6 Roller ensure Consistent seed spacing and flow.
Seed box capacity - 5kg - Balanced nutrition per row with every pass.
