insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('5077', 'UNG_A1772518016839', 'UNG Agros', 'Small Cultiweeder (Mini Hand Cultivator)', 'Large Cultiweeder - Heavy-Duty Garden Cultivator for Efficient Weeding & Soil Preparation
Transform your gardening experience with the Large Cultiweeder, a robust and ergonomic soil cultivation tool designed for effortless weeding, soil loosening, aeration, and bed preparation. Whether you''re working in a backyard vegetable garden, nursery plot, terrace planters, or larger garden beds, this cultivator delivers powerful performance with minimal effort.
Crafted for strength, comfort, and longevity, the Large Cultiweeder features a heavy-duty head with multiple hardened steel tines that penetrate deep into the soil, breaking up compacted earth, uprooting stubborn weeds, and improving soil structure for healthier, more productive plants. The long, ergonomic handle keeps you upright while working, reducing back strain and fatigue during extended use.
&#127807; Key Benefits
Efficient Weeding & Cultivation: The wide working head covers more soil in every pass, dramatically reducing the time and effort needed to remove weeds and prepare beds.
Enhanced Soil Aeration: Deep-penetrating tines loosen compact soil and improve oxygen circulation, helping plant roots grow stronger and absorb nutrients more effectively.
Reduced Physical Strain: A long, balanced handle allows for comfortable standing use, eliminating the need to bend or kneel repeatedly.
Durable Construction: Made from high-quality carbon or stainless steel with anti-corrosion coating, this tool is built to withstand frequent outdoor use and tough soil conditions.
Versatile Garden Use: Ideal for vegetable plots, flower beds, herbs, shrub borders, and landscaping soil preparation &#8212; from fine seedbeds to heavier clay soils.
&#128736;&#65039; Features & Design
Heavy-Duty Tines: Multiple hardened steel prongs are spaced for optimal soil turnover and weed extraction without damaging plant roots.
Ergonomic Long Handle: Designed for user comfort, the extended handle provides excellent leverage and control while reducing bending.
Wide Working Width: Larger head size allows you to cover more ground with fewer strokes, increasing gardening efficiency.
Comfort Grip: Non-slip, cushioned grip reduces hand fatigue and enhances handling even when hands are wet or sweaty.
Easy Maintenance: Simple to clean and maintain &#8212; wipe off soil after use and store in a dry place for lasting life.', 'https://innovationguild.in/innovation/5077/small-cultiweeder-mini-hand-cultivator', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772688523545-Culti-9.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772688523545-Culti-9.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772688554009-Culti-5.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772688568798-Culti-6.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772688586143-Culti-8.jpg"]'::jsonb, '[]'::jsonb, '#32, 1st main, 2nd cross, Muneshwara layout, Laggere, Bengaluru - 560058 | Karnataka, India', '{"Agriculture"}', '{"Production","Maintenance and management"}', '[{"key":"Power Source","value":"Manual","code":"CHANGEMAKER_META_CODE.POWER_SOURCE"},{"key":"Maximum cost of product","value":"Not listed","code":"CHANGEMAKER_META_CODE.MAXIMUM_COST_OF_PRODUCT"},{"key":"Engine Details","value":"na","code":"CHANGEMAKER_META_CODE.ENGINE_DETAILS"},{"key":"Number of Unit Installed","value":"1000+","code":"CHANGEMAKER_META_CODE.NUM_OF_UNITS_INSTALLED"},{"key":"Performance Parameters","value":"na","code":"CHANGEMAKER_META_CODE.PERFORMANCE_PARAMETERS"},{"key":"Technical Training","value":"No","code":"CHANGEMAKER_META_CODE.TECHNICAL_TRAINING"},{"key":"Year Launched","value":"2018","code":"CHANGEMAKER_META_CODE.YEAR_LAUNCHED"},{"key":"Suitable Crops","value":"all types","code":"CHANGEMAKER_META_CODE.SUITABLE_CROPS"},{"key":"Spare Parts for Product","value":"yes","code":"CHANGEMAKER_META_CODE.SPARE_PARTS_FOR_PRODUCT"},{"key":"Product Weight","value":"1.1kg approx","code":"CHANGEMAKER_META_CODE.PRODUCT_WEIGHT"},{"key":"Minimum cost of product","value":"1","code":"CHANGEMAKER_META_CODE.MINIMUM_COST_OF_PRODUCT"},{"key":"Training on Maintenance and Aft