insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('4823', 'GRAIN1762252229351', 'Grain Shell', 'Solar Mobile Dryer', 'Grain shell Solar Mobile Dryer (SMD2000/SMD4000) is a collapsible, tunnel type dryer with 2 ton (2000Kg)/4 ton (4000kg) drying capacity designed to protect the agricultural commodity from uneven / sudden rains during drying, and to prevent spillage and contamination damage. Drying efficiency is dependent on the solar radiation, relative humidity of the ambient air, and moisture content of concerned agricultural commodity. The Solar Mobile Dryer consists of semi-transparent cover made of UV Resistant Poly film/cross laminated film connected to the black fabric coated PVC film by a high strength zipper. Through the semi-transparent top cover, solar radiation enters the drying chamber and heats of the agricultural commodity being dried. Moisture in the commodity is evaporated and pushed by the DC Fans out from the drying chamber. The Solar Mobile Dryer SMD2000/SMD4000 drying possible even during unexpected rain conditions. It can dry grains, seeds, nuts, coffee beans, Cocoa beans, spices, oil seeds at an average drying rate of 0.5 to 1.0% per hour on grains. However, during full sunny condition drying time is about 24 hours on a moisture content reduce 28 to 14%.', 'https://innovationguild.in/innovation/4823/solar-mobile-dryer', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1770796921283-service-3.jpg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1770796921283-service-3.jpg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1770796921338-service-4.jpg"]'::jsonb,