insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('5066', 'UNG_A1772531045640', 'UNG Agros', 'Stirrup Hoe 5.5 Inch – Manual Weed Remover & Soil Loosener', 'The Stirrup Hoe - 5.5 Inch is a durable and efficient soil cultivator tool crafted for farmers, gardeners, and horticulture professionals. Built with a high-quality carbon steel blade, this hoe provides sharp, smooth cutting action that easily removes weeds without disturbing surrounding crops.
The specially designed curved blade works in a push-pull motion, allowing faster weed removal with less effort. Its 5.5-inch width makes it perfect for working between crop rows, vegetable beds, and garden plants.
The ergonomic grip ensures comfortable operation, reducing hand strain during long working hours. The sturdy frame construction adds durability and stability, making it suitable for regular agricultural use.
This tool not only removes weeds but also loosens and aerates soil, promoting healthier plant growth and improved water absorption.
&#128313; Key Features
5.5-inch curved carbon steel blade
Smooth push-pull cutting action
Ergonomic and comfortable grip
Strong & durable frame
Ideal for agriculture, gardening & nurseries
