insert into public.innovation_guild_products (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('5069', 'PRABH1761808480582', 'Prabhath Industries', 'Turmeric Boiling Unit', 'Typically Turmeric is boiled in the water with the help of Huge containers and boilers, farmers struggle a lot to boil water and transfer the hot turmeric from the boiler, the water used in the boiling unit absorbs most of the minerals and important qualities of turmeric in the process, So i have designed a Turmeric boiling Cooker which cooks the turmeric with the help of steam and not immersed in the water, Thus the water intake in the boiling will be less and the turmeric circumin levels will be maintained properly and the pressurised steam helps to cook the turmeric quickly compared to traditional Cooking methods.', 'https://innovationguild.in/innovation/5069/turmeric-boiling-unit', 'https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772532954519-WhatsApp_Image_2026-02-02_at_4.57.58_PM.jpeg', '["https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772532954519-WhatsApp_Image_2026-02-02_at_4.57.58_PM.jpeg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772532954490-WhatsApp_Image_2026-02-02_at_4.57.58_PM_%281%29.jpeg","https://attachment-ms.s3.ap-south-1.amazonaws.com/1804/opportunity_gallery/1772532954580-WhatsApp_Image_2026-02-02_at_5.00.22_PM.jpeg"]'::jsonb, '[]'::jsonb, '6VGVGVJJ+6C | Telangana, India', '{"Agriculture"}', '{"Processing"}', '[{"key":"Demo Installations","value":"no","code":"CHANGEMAKER_META_CODE.DEMO_INSTALLATIONS"},{"key":"Suitable Terrains","value":"NA","code":"CHANGEMAKER_META_CODE.SUITABLE_TERRAINS"},{"key":"Minimum cost of product","